import sqlite3
import threading
import os
from contextlib import contextmanager
from typing import Optional

class FileAccessControl:
    def __init__(self, db_path: str):
        self.db_path = db_path
        self.file_locks = {}
        self.locks_lock = threading.Lock()
        self._init_db()
    
    def _init_db(self):
        conn = sqlite3.connect(self.db_path)
        cursor = conn.cursor()
        cursor.execute('''
            CREATE TABLE IF NOT EXISTS permissions (
                user_id TEXT,
                file_path TEXT,
                access_level TEXT,
                PRIMARY KEY (user_id, file_path)
            )
        ''')
        conn.commit()
        conn.close()
    
    def _get_file_lock(self, file_path: str) -> threading.Lock:
        with self.locks_lock:
            if file_path not in self.file_locks:
                self.file_locks[file_path] = threading.Lock()
            return self.file_locks[file_path]
    
    @contextmanager
    def _get_db_connection(self):
        conn = sqlite3.connect(self.db_path, timeout=10.0)
        conn.execute("BEGIN IMMEDIATE")
        try:
            yield conn
            conn.commit()
        except Exception:
            conn.rollback()
            raise
        finally:
            conn.close()
    
    def grant_permission(self, user_id: str, file_path: str, access_level: str):
        with self._get_db_connection() as conn:
            cursor = conn.cursor()
            cursor.execute('''
                INSERT OR REPLACE INTO permissions (user_id, file_path, access_level)
                VALUES (?, ?, ?)
            ''', (user_id, file_path, access_level))
    
    def revoke_permission(self, user_id: str, file_path: str):
        with self._get_db_connection() as conn:
            cursor = conn.cursor()
            cursor.execute('''
                DELETE FROM permissions WHERE user_id = ? AND file_path = ?
            ''', (user_id, file_path))
    
    def _check_permission_in_transaction(self, conn: sqlite3.Connection, 
                                        user_id: str, file_path: str) -> bool:
        cursor = conn.cursor()
        cursor.execute('''
            SELECT access_level FROM permissions 
            WHERE user_id = ? AND file_path = ?
        ''', (user_id, file_path))
        result = cursor.fetchone()
        return result is not None and result[0] in ['read', 'write', 'admin']
    
    def read_file(self, user_id: str, file_path: str) -> Optional[str]:
        file_lock = self._get_file_lock(file_path)
        
        with file_lock:
            with self._get_db_connection() as conn:
                has_permission = self._check_permission_in_transaction(conn, user_id, file_path)
                
                if not has_permission:
                    raise PermissionError(f"User {user_id} does not have permission to read {file_path}")
                
                if not os.path.exists(file_path):
                    raise FileNotFoundError(f"File {file_path} does not exist")
                
                with open(file_path, 'r') as f:
                    content = f.read()
                
                return content
    
    def read_file_binary(self, user_id: str, file_path: str) -> Optional[bytes]:
        file_lock = self._get_file_lock(file_path)
        
        with file_lock:
            with self._get_db_connection() as conn:
                has_permission = self._check_permission_in_transaction(conn, user_id, file_path)
                
                if not has_permission:
                    raise PermissionError(f"User {user_id} does not have permission to read {file_path}")
                
                if not os.path.exists(file_path):
                    raise FileNotFoundError(f"File {file_path} does not exist")
                
                with open(file_path, 'rb') as f:
                    content = f.read()
                
                return content
    
    def write_file(self, user_id: str, file_path: str, content: str):
        file_lock = self._get_file_lock(file_path)
        
        with file_lock:
            with self._get_db_connection() as conn:
                cursor = conn.cursor()
                cursor.execute('''
                    SELECT access_level FROM permissions 
                    WHERE user_id = ? AND file_path = ?
                ''', (user_id, file_path))
                result = cursor.fetchone()
                
                if result is None or result[0] not in ['write', 'admin']:
                    raise PermissionError(f"User {user_id} does not have write permission for {file_path}")
                
                with open(file_path, 'w') as f:
                    f.write(content)


